package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testPrintRecord() throws IOException {
        // Given
        StringWriter out = new StringWriter();
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        csvFormat.printRecord(out, "value1", "value2", "value3");

        // Then
        assertEquals("value1,value2,value3\r\n", out.toString());
    }

    @Test
    void testPrintRecord_EmptyValues() throws IOException {
        // Given
        StringWriter out = new StringWriter();
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        csvFormat.printRecord(out);

        // Then
        assertEquals("\r\n", out.toString());
    }
}
